from azure.ai.projects import AgentClient
from time import perf_counter

client = AgentClient.from_azure_ai_project('your-project-id')

def monitor_grounding_latency(thread_id):
    metrics = client.get_thread_metrics(thread_id)
    grounding_tokens = 0
    for step in metrics['steps']:
        if step['type'] == 'grounding':
            grounding_tokens += step['input_tokens']

    if grounding_tokens > 50000:
        print(f'⚠️ GROUNDING BLOAT: {grounding_tokens} tokens')
        return {'alert': 'high', 'tokens': grounding_tokens}
    return {'status': 'healthy'}

from azure.ai.projects import AgentClient

def detect_tool_loops(thread_id):
    client = AgentClient.from_azure_ai_project('your-project-id')
    thread = client.get_thread(thread_id)

    tool_calls = [step for step in thread.steps if step.type == 'tool_call']
    if len(tool_calls) > 4:
        loop_time = sum(step.duration_ms for step in tool_calls) / 1000
        print(f'🔄 TOOL LOOP: {len(tool_calls)} calls, {loop_time:.1f}s')
        return {'alert': 'critical', 'loop_count': len(tool_calls)}
    return {'status': 'ok'}

import asyncio
from azure.ai.projects import StreamingClient

async def measure_streaming_latency(thread_id):
    client = StreamingClient.from_azure_ai_project('your-project-id')
    first_token_time = None
    last_token_time = None

    async for event in client.stream_thread(thread_id):
        if event.type == 'token' and first_token_time is None:
            first_token_time = perf_counter()
        last_token_time = perf_counter()

    if first_token_time and last_token_time:
        latency_gap = last_token_time - first_token_time
        if latency_gap > 5.0:
            print(f'⏳ STREAMING GAP: {latency_gap:.1f}s')
            return {'alert': 'high', 'gap': latency_gap}
    return {'status': 'healthy'}

