from fastapi import FastAPI
from azure.ai.projects import StreamingClient

app = FastAPI()

@app.post('/chat/{thread_id}')
async def stream_chat(thread_id: str, message: str):
    client = StreamingClient.from_azure_ai_project('your-project-id')

    async def stream_generator():
        await client.send_message(thread_id, message)
        async for event in client.stream_thread(thread_id):
            if event.type == 'token':
                yield {'delta': event.content}
            elif event.type == 'done':
                break

    return StreamingResponse(stream_generator(), media_type='text/plain')

