from vex_sdk import Vex
from azure.ai.projects import AgentClient

# Install: pip install azure-ai-projects vex-sdk

vex = Vex(project_id='your-vex-project')

@vex.detector('azure-agent-latency', cron='*/5 * * * *')
def monitor_agent_latency():
    client = AgentClient.from_azure_ai_project('your-project-id')

    # Scan all active threads
    for thread in client.list_threads(status='active'):
        metrics = client.get_thread_metrics(thread.id)

        # Latency anomaly detection
        if metrics['grounding_tokens'] > 50000:
            vex.trigger_remediation(
                thread_id=thread.id,
                issue='grounding_bloat',
                fix='limit_bing_tokens',
                config={'max_tokens': 8000}
            )

        if metrics['tool_calls'] > 4:
            vex.trigger_remediation(
                thread_id=thread.id,
                issue='tool_loop',
                fix='truncate_context',
                config={'max_tokens': 28000}
            )

    print('✅ Vex latency monitoring complete')

vex.deploy()
